// ADT 风格的环形缓冲区接口定义
#ifndef CIRCBUF_H
#define CIRCBUF_H

#include <stdint.h>
#include <stdbool.h>

#define CIRC_BUF_SIZE 1024

typedef struct {
    uint8_t buffer[CIRC_BUF_SIZE];
    volatile uint16_t head;  /* DMA 写入位置 */
    volatile uint16_t tail;  /* CPU 读取位置 */
    volatile uint16_t overflow_count;  /* 溢出计数器 */
} circ_buf_t;

void circbuf_init(circ_buf_t *cb);
uint16_t circbuf_count(const circ_buf_t *cb);
bool circbuf_get(circ_buf_t *cb, uint8_t *byte);
uint16_t circbuf_get_batch(circ_buf_t *cb, uint8_t *dst, uint16_t max_len);
void circbuf_dma_advance_head(circ_buf_t *cb, uint16_t bytes_transferred);

#endif

/* USART1 + DMA2 Stream5 循环接收初始化 */
#define RX_BUF_SIZE  1024
static uint8_t rx_buffer[RX_BUF_SIZE];
static volatile uint16_t dma_rx_count = 0;

void uart1_dma_init(void)
{
    /* 1. 使能 USART1 和 DMA2 时钟 */
    __HAL_RCC_USART1_CLK_ENABLE();
    __HAL_RCC_DMA2_CLK_ENABLE();
    __HAL_RCC_GPIOA_CLK_ENABLE();  /* PA9=TX, PA10=RX */

    /* 2. 配置 GPIO: PA9=AF7(USART1_TX), PA10=AF7(USART1_RX) */
    GPIO_InitTypeDef gpio = {0};
    gpio.Pin = GPIO_PIN_9 | GPIO_PIN_10;
    gpio.Mode = GPIO_MODE_AF_PP;
    gpio.Pull = GPIO_PULLUP;
    gpio.Speed = GPIO_SPEED_FREQ_HIGH;
    gpio.Alternate = GPIO_AF7_USART1;
    HAL_GPIO_Init(GPIOA, &gpio);

    /* 3. 配置 DMA2 Stream5 for USART1_RX */
    hdma_usart1_rx.Instance = DMA2_Stream5;
    hdma_usart1_rx.Init.Channel = DMA_CHANNEL_4;  /* USART1_RX 映射到 Channel 4 */
    hdma_usart1_rx.Init.Direction = DMA_PERIPH_TO_MEMORY;  /* 外设->内存 */
    hdma_usart1_rx.Init.PeriphInc = DMA_PINC_DISABLE;  /* 外设地址不递增 */
    hdma_usart1_rx.Init.MemInc = DMA_MINC_ENABLE;  /* 内存地址递增 */
    hdma_usart1_rx.Init.PeriphDataAlignment = DMA_PDATAALIGN_BYTE;
    hdma_usart1_rx.Init.MemDataAlignment = DMA_MDATAALIGN_BYTE;
    hdma_usart1_rx.Init.Mode = DMA_CIRCULAR;  /* 循环模式 */
    hdma_usart1_rx.Init.Priority = DMA_PRIORITY_LOW;
    HAL_DMA_Init(&hdma_usart1_rx);

    /* 4. 关联 DMA 到 USART1 RX */
    __HAL_LINKDMA(&huart1, hdmarx, hdma_usart1_rx);

    /* 5. 配置 USART1: 115200, 8N1 */
    huart1.Instance = USART1;
    huart1.Init.BaudRate = 115200;
    huart1.Init.WordLength = UART_WORDLENGTH_8B;
    huart1.Init.StopBits = UART_STOPBITS_1;
    huart1.Init.Parity = UART_PARITY_NONE;
    huart1.Init.Mode = UART_MODE_TX_RX;
    huart1.Init.HwFlowCtl = UART_HWCONTROL_NONE;
    HAL_UART_Init(&huart1);

    /* 6. 启动 DMA 循环接收 */
    HAL_UARTEx_ReceiveToIdle_DMA(&huart1, rx_buffer, RX_BUF_SIZE);
}

/* DMA 半传输回调 - 在 DMA_HT 中断中调用 */
void HAL_UARTEx_RxEventCallback(UART_HandleTypeDef *huart, uint16_t size)
{
    if (huart->Instance == USART1) {
        /* 先处理已有数据，再更新索引 */
        dma_rx_count += size;
        /* 此处应调用 circbuf_dma_advance_head() 处理数据 */
    }
}

// 陷阱三修复：正确的 DMA 中断服务函数
void DMA2_Stream5_IRQHandler(void)
{
    /* 必须检查 LISR 中的 HTIF5 和 TCIF5，不能只查 HT */
    if (__HAL_DMA_GET_FLAG(&hdma_usart1_rx, DMA_FLAG_HTIF5)) {
        /* 半传输中断：前 512 字节已完成 */
        __HAL_DMA_CLEAR_FLAG(&hdma_usart1_rx, DMA_FLAG_HTIF5);
        process_partial_data(rx_buffer, 512);
    }
    if (__HAL_DMA_GET_FLAG(&hdma_usart1_rx, DMA_FLAG_TCIF5)) {
        /* 完整传输中断：后 512 字节已完成 */
        __HAL_DMA_CLEAR_FLAG(&hdma_usart1_rx, DMA_FLAG_TCIF5);
        process_partial_data(rx_buffer + 512, 512);
    }
}

// 陷阱二修复：无锁溢出的 head/tail 设计
static volatile uint32_t dma_head = 0;  /* 不回绕，持续递增 */
static volatile uint32_t cpu_tail = 0;  /* 不回绕，持续递增 */

static inline uint32_t circbuf_available(void)
{
    uint32_t h = dma_head;
    uint32_t t = cpu_tail;
    return (h >= t) ? (h - t) : 0;
}

static inline bool circbuf_is_overflow(uint32_t capacity)
{
    return circbuf_available() > capacity;
}

/* ========== 重构前：裸指针全局变量（坏味道：数据泥团 + 过长函数）========== */
uint8_t rx_buf[1024];
int rx_pos = 0;
int rx_total = 0;

void DMA2_Stream5_IRQHandler(void)
{
    if (__HAL_DMA_GET_FLAG(&hdma, DMA_FLAG_TCIF5)) {
        __HAL_DMA_CLEAR_FLAG(&hdma, DMA_FLAG_TCIF5);
        rx_pos += 512;  /* 硬编码 512！ */
        rx_total += 512;
        process_rx_data(rx_buf, rx_pos);  /* 裸指针传入，谁都能改 */
    }
}

void process_rx_data(uint8_t *buf, int pos)
{
    /* 遍历整个缓冲区找帧头 0xAA */
    for (int i = 0; i < pos; i++) {  /* 每次都从头扫描！ */
        if (buf[i] == 0xAA) {
            /* 解析帧... */
        }
    }
}

/* ========== 重构后：ADT 封装 + 溢出保护 ========== */
#define CIRC_BUF_SIZE 1024

typedef struct {
    uint8_t buffer[CIRC_BUF_SIZE];
    volatile uint16_t head;
    volatile uint16_t tail;
    volatile uint16_t overflow;
} circ_buf_t;

static circ_buf_t uart1_rx_cb;

static inline uint16_t circbuf_used(const circ_buf_t *cb)
{
    uint16_t h = cb->head, t = cb->tail;
    return (h >= t) ? (h - t) : (CIRC_BUF_SIZE - t + h);
}

uint16_t circbuf_drain(circ_buf_t *cb, void (*handler)(const uint8_t *, uint16_t))
{
    uint16_t available = circbuf_used(cb);
    if (available == 0) return 0;

    /* 批量处理，减少临界区 */
    uint16_t consumed = 0;
    while (consumed < available) {
        uint16_t chunk = (available - consumed > 64) ? 64 : (available - consumed);
        handler(cb->buffer + cb->tail, chunk);
        cb->tail = (cb->tail + chunk) % CIRC_BUF_SIZE;
        consumed += chunk;
    }
    return consumed;
}

void DMA2_Stream5_IRQHandler(void)
{
    if (__HAL_DMA_GET_FLAG(&hdma, DMA_FLAG_TCIF5)) {
        __HAL_DMA_CLEAR_FLAG(&hdma, DMA_FLAG_TCIF5);
        uint16_t transferred = 512;
        uint16_t new_head = (uart1_rx_cb.head + transferred) % CIRC_BUF_SIZE;

        /* 溢出检测 */
        uint16_t before = circbuf_used(&uart1_rx_cb);
        uart1_rx_cb.head = new_head;
        uint16_t after = circbuf_used(&uart1_rx_cb);
        if (after <= before || after > CIRC_BUF_SIZE / 2) {
            uart1_rx_cb.overflow++;  /* CPU 消费太慢，数据被覆盖 */
        }

        circbuf_drain(&uart1_rx_cb, frame_parser_handler);
    }
}
